import React, {useState} from 'react';
import { TransformWrapper, TransformComponent } from "react-zoom-pan-pinch";
import styles from './StarsRoot.module.scss';
import Grid from "../Grid";

const StarsRoot = (props) => {
    const [zoom, setZoom] = useState(1);
    const [debounce, setDebounce] = useState(false);

    const handleZoomChange = (e) => {
        setZoom(e?.scale === 1);
    }

    return (
        <div className={styles.root}>
            <TransformWrapper
                defaultScale={1}
                defaultPositionX={100}
                defaultPositionY={200}
                wheel={{
                    step: 200,
                }}
                scalePadding={{
                    disabled: true,
                    animationTime: 50,
                    animationType: 'linear',
                }}
                pan={{
                    animationTime: 50,
                    lockAxisY: zoom,
                    lockAxisX: zoom,
                }}
                onWheelStop={handleZoomChange}
                onPanningStop={handleZoomChange}
            >
                {(transformParam) => (
                    <>
                        <div className={styles.tools}>
                            <button onClick={(e) => {
                                setTimeout(() => {
                                    transformParam.zoomIn(e);
                                    setTimeout(() => setZoom(transformParam?.scale), 200);
                                },)
                            }}>+</button>
                            <button onClick={(e) => {
                                setTimeout(() => {
                                    transformParam.zoomOut(e);
                                    const scale = transformParam?.scale;
                                    setTimeout(() => setZoom(scale), 200);
                                }, )
                            }}>-</button>
                        </div>
                        <TransformComponent>
                               <Grid transformParam={transformParam} />
                        </TransformComponent>
                    </>
                )}
            </TransformWrapper>
        </div>
    );
};

StarsRoot.propTypes = {};

StarsRoot.defaultProps = {};

export default StarsRoot;
