import React, {useEffect, useRef, useState} from 'react';
import PropTypes from 'prop-types';
import styles from './Canvas.module.scss';

const Canvas = (props) => {
    const { maxX, maxY, hoverGroup, coordinates } = props;
    const ref = useRef();
    const [param, setParam] = useState({ width: 0, height: 0});

    const drawSector = () => {
        if (hoverGroup) {
            const activeSector = [...coordinates].filter(item => item.group === hoverGroup);
            activeSector.sort((a, b) => +a.drawNumber - +b.drawNumber);

            const ctx = ref.current.getContext('2d');
            ctx.fillStyle = 'rgba(255,255,255,0.1)';
            ctx.strokeStyle = 'rgba(255,255,255,0.3)';
            ctx.beginPath();
            ctx.moveTo(activeSector[0]?.clientX,activeSector[0]?.clientY);
            for (let i = 1; i <= activeSector.length; i++) {
                ctx.lineTo(activeSector[i]?.clientX, activeSector[i]?.clientY);
            }
            ctx.lineTo(activeSector[0]?.clientX,activeSector[0]?.clientY);
            ctx.stroke();
            ctx.fill();
        } else {
            drawGrid();
        }
    }

    useEffect(() => {
        drawSector();
    }, [hoverGroup]);


    const drawGrid = () => {
        const width =  window.innerWidth;
        const height = window.innerHeight;
        const xStep = window.innerWidth / maxX;
        const yStep = window.innerHeight / maxY;

        const ctx = ref.current.getContext('2d');
        ctx.clearRect(0,0, width, height);
        ctx.strokeStyle = '#222222';
        ctx.lineWidth = 1;


        const drawHeightLine = (value) => {
            ctx.beginPath();
            ctx.moveTo(0, value);
            ctx.lineTo(width, value);
            ctx.stroke();
        }

        const drawWidthLine = (value) => {
            ctx.beginPath();
            ctx.moveTo(value, 0);
            ctx.lineTo(value, height);
            ctx.stroke();
        }

        for (let i = 30; i < height; i += 30) {
            drawHeightLine(i);
        }

        for (let i = 30; i < width; i += 30) {
            drawWidthLine(i);
        }
    }

    const onResize = () => {
        const width =  window.innerWidth;
        const height = window.innerHeight;
        setParam({ width, height })
    }

    useEffect(() => {
        onResize();
        window.addEventListener('resize', onResize);
        return () => {
            window.removeEventListener('resize', onResize);
        };
    }, []);

    useEffect(() => {
        drawGrid();
    }, [param]);




    useEffect(() => {
        drawGrid();
    }, [])

    return (
  <div className={styles.root}>
      <div className={styles.canvas}>
          <canvas ref={ref} width={param.width} height={param.height}/>
      </div>
  </div>
    );
};

Canvas.propTypes = {
    maxX: PropTypes.number.isRequired,
    maxY: PropTypes.number.isRequired,
    hoverGroup: PropTypes.string.isRequired,
    coordinates: PropTypes.array.isRequired,
};

Canvas.defaultProps = {};

export default Canvas;
