import React, { useMemo, useRef, useEffect } from 'react';
import PropTypes from 'prop-types';
import classNames from "classnames";
import styles from './StarContainer.module.scss';


const StarContainer = (props) => {
    const { name, group, x, y, id, isHovered, setHoverGroup, transformParam, setCoordinates, drawNumber } = props;
    const ref = useRef();

    const handleMouseEnter = () => {
        setHoverGroup(group);
    }

    const handleMouseLeave = () => {
        setHoverGroup(null);
    }

    const handleClick = (e) => {
        const { x: clientX, y: clientY, height, width } = ref.current.getBoundingClientRect();
        transformParam.setTransform(-clientX - width, -clientY - height, 2, 100, 'linear');
    }

    const setHoverParam = () => {
        const { x: clientX, y: clientY } = ref.current.getBoundingClientRect();
        setCoordinates(state => {
            const newState = [...state];
            const index = newState.findIndex(item => item.id === id);
            if (index > -1) {
                newState[index] = { drawNumber, clientX: clientX - 70, clientY: clientY - 170, group, id }
            } else {
                newState.push({ drawNumber, clientX: clientX - 70, clientY: clientY - 170, group, id });
            }
            return newState;
        })
    }

    const setResizeHoverParam = () => {
        const { x: clientX, y: clientY } = ref.current.getBoundingClientRect();
        setCoordinates(state => {
            const newState = [...state];
            const index = newState.findIndex(item => item.id === id);
            if (index > -1) {
                newState[index] = { drawNumber, clientX: clientX + 30, clientY: clientY + 30, group, id }
            } else {
                newState.push({ drawNumber, clientX: clientX + 30, clientY: clientY + 30, group, id });
            }
            return newState;
        })
    }

    useEffect(() => {
        window.addEventListener('resize', setResizeHoverParam)

        return () => {
            window.removeEventListener('resize', setResizeHoverParam)
        };
    }, [])



    useEffect(() => {
        setHoverParam();
    }, [ref]);

    return useMemo( () => (
        <div className={styles.root} style={{ gridArea: `${y} / ${x}` }}>
            <div className={classNames(styles.wrapper, {[styles.hovered]: isHovered})} ref={ref} id={`id${id}`}>
                <button className={classNames(styles.star, {[styles.hovered]: isHovered})} onMouseEnter={handleMouseEnter} onMouseLeave={handleMouseLeave} onClick={handleClick}/>
                <span key={name}>{name}</span>
                <span key={group}>{group}</span>
            </div>
        </div>
    ), [isHovered]);
};

StarContainer.propTypes = {
    name: PropTypes.string.isRequired,
    group: PropTypes.string.isRequired,
    id: PropTypes.string.isRequired,
    drawNumber: PropTypes.number.isRequired,
    x: PropTypes.number.isRequired,
    y: PropTypes.number.isRequired,
    isHovered: PropTypes.bool.isRequired,
    setHoverGroup: PropTypes.func.isRequired,
    transformParam: PropTypes.object.isRequired,
    setCoordinates: PropTypes.func.isRequired,
};

StarContainer.defaultProps = {};

export default StarContainer;
