const Grid = (props) => {
    const { transformParam } = props;
    const [hoverGroup, setHoverGroup] = useState(null);
    const [coordinates, setCoordinates] = useState([])

    // console.log(coordinates);

    const { xLength, yLength } = checkGridSize(stars);

    return (
        <div className={styles.root}>
            <div className={styles.canvasGrid}>
                <Canvas maxX={xLength+1} maxY={yLength+1} hoverGroup={hoverGroup} coordinates={coordinates} />
            </div>
        <div className={styles.grid} style={{ gridTemplateColumns: `repeat(${xLength+1}, 1fr`, gridTemplateRows: `repeat(${yLength+1}, 1fr` }}>
            {stars.map(({ name, group, id, x, y, drawNumber  }) => <StarContainer
                key={`${group}-${name}-${id}`}
                name={name} group={group}
                drawNumber={drawNumber}
                id={id}
                x={x}
                y={y}
                isHovered={hoverGroup === group}
                setHoverGroup={setHoverGroup}
                transformParam={transformParam}
                setCoordinates={setCoordinates}
            />)}
        </div>
        </div>
    );
};

Grid.propTypes = {
    transformParam: PropTypes.object.isRequired,
};

Grid.defaultProps = {};

export default Grid;

